1	import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
2	import { Interval } from '@nestjs/schedule';
3	
4	import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
5	import { EnvConfigService } from '@modules/env-config/env-config.service';
6	import { OpensearchService } from '@modules/opensearch/opensearch.service';
7	
8	import {
9		NEURAL_SEARCH_LIMIT,
10		NEURAL_SEARCH_MAX_QUERY_LENGTH,
11	} from '@constants/common.constant';
12	import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
13	import {
14		NEURAL_SEARCH_CONTRACTIONS,
15		NEURAL_SEARCH_KNOWN_BRANDS,
16		NEURAL_SEARCH_KNOWN_COLORS,
17		NEURAL_SEARCH_KNOWN_SIZES,
18	} from '@constants/neural-search.constant';
19	
20	import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';
21	
22	import { LogExecution } from '@decorators/log-execution.decorator';
23	
24	const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
25	
26	const MODEL_GROUP_NAME = 'neural-search-model-group';
27	
28	@Injectable()
29	export class OpensearchNeuralService implements OnModuleInit {
30		private readonly logger = new Logger(OpensearchNeuralService.name);
31		private indexName: string;
32		private modelId: string | null = null;
33	
34		constructor(
35			private readonly opensearchService: OpensearchService,
36			private readonly configService: EnvConfigService,
37		) {}
38	
39		async onModuleInit(): Promise<void> {
40			this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
41			await this.resolveModelId();
42	
43			if (!this.modelId) {
44				await this.attemptAutoRedeploy();
45			}
46		}
47	
48		@Interval(MODEL_REFRESH_INTERVAL_MS)
49		async refreshModelId(): Promise<void> {
50			await this.resolveModelId();
51		}
52	
53		private async resolveModelId(): Promise<void> {
54			try {
55				const modelId = await this.opensearchService.findDeployedModelId({
56					modelGroupName: MODEL_GROUP_NAME,
57				});
58	
59				if (modelId && modelId !== this.modelId) {
60					const previousModelId = this.modelId;
61					this.modelId = modelId;
62					this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
63				} else if (!modelId) {
64					this.logger.warn(
65						'No deployed model found. Neural search will not work until bootstrap is run.',
66					);
67				}
68			} catch {
69				this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
70			}
71		}
72	
73		private async attemptAutoRedeploy(): Promise<void> {
74			try {
75				this.logger.log('Attempting auto-redeploy of neural search model...');
76				const modelId = await this.opensearchService.redeployRegisteredModel({
77					modelGroupName: MODEL_GROUP_NAME,
78				});
79	
80				if (modelId) {
81					this.modelId = modelId;
82					this.logger.log(`Auto-redeploy successful. Model ID: ${modelId}`);
83				} else {
84					this.logger.warn(
85						'No registered model found for auto-redeploy. Run: npm run cli:dev -- bootstrap-neural-search',
86					);
87				}
88			} catch {
89				this.logger.warn('Auto-redeploy failed. OpenSearch may not be available.');
90			}
91		}
92	
93		private getModelId(): string {
94			if (!this.modelId) {
95				throw new Error(
96					'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
97				);
98			}
99			return this.modelId;
100		}
101	
102		private detectBrand({ text }: { text: string }): string | null {
103			const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
104			for (const brand of sorted) {
105				const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
106				if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
107					return brand;
108				}
109			}
110			return null;
111		}
112	
113		private detectColor({ text }: { text: string }): string | null {
114			const sorted = [...NEURAL_SEARCH_KNOWN_COLORS].sort((a, b) => b.length - a.length);
115			for (const color of sorted) {
116				const escaped = color.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
117				if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
118					return color;
119				}
120			}
121			return null;
122		}
123	
124		private readonly MEASUREMENT_UNITS_PATTERN =
125			/\b\d+\s*(?:oz|ounce|ml|liter|litre|gal|gallon|inch|in|cm|mm|ft|foot|feet)\b/i;
126	
127		private readonly PRICE_RANGE_PATTERNS: {
128			pattern: RegExp;
129			extract: ({
130				match,
131			}: {
132				match: RegExpExecArray;
133			}) => { min: number | null; max: number | null } | null;
134		}[] = [
135			{
136				pattern: /\b(?:under|below|less\s+than|up\s+to)\s+\$(\d+(?:\.\d{1,2})?)/i,
137				extract: ({ match }) => {
138					const max = parseFloat(match[1] ?? '');
139					return isNaN(max) ? null : { min: null, max };
140				},
141			},
142			{
143				pattern: /\bfrom\s+\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
144				extract: ({ match }) => {
145					const min = parseFloat(match[1] ?? '');
146					const max = parseFloat(match[2] ?? '');
147					return isNaN(min) || isNaN(max) ? null : { min, max };
148				},
149			},
150			{
151				pattern: /\$(\d+(?:\.\d{1,2})?)\s*[-–]\s*\$(\d+(?:\.\d{1,2})?)/i,
152				extract: ({ match }) => {
153					const min = parseFloat(match[1] ?? '');
154					const max = parseFloat(match[2] ?? '');
155					return isNaN(min) || isNaN(max) ? null : { min, max };
156				},
157			},
158			{
159				pattern: /\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
160				extract: ({ match }) => {
161					const min = parseFloat(match[1] ?? '');
162					const max = parseFloat(match[2] ?? '');
163					return isNaN(min) || isNaN(max) ? null : { min, max };
164				},
165			},
166			{
167				pattern: /\bto\s+\$(\d+(?:\.\d{1,2})?)/i,
168				extract: ({ match }) => {
169					const max = parseFloat(match[1] ?? '');
170					return isNaN(max) ? null : { min: null, max };
171				},
172			},
173			{
174				pattern: /\b(?:over|above|more\s+than|from)\s+\$(\d+(?:\.\d{1,2})?)/i,
175				extract: ({ match }) => {
176					const min = parseFloat(match[1] ?? '');
177					return isNaN(min) ? null : { min, max: null };
178				},
179			},
180			{
181				pattern: /\b(?:around|about|~)\s*\$(\d+(?:\.\d{1,2})?)/i,
182				extract: ({ match }) => {
183					const price = parseFloat(match[1] ?? '');
184					return isNaN(price)
185						? null
186						: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
187				},
188			},
189			{
190				pattern: /\$(\d+(?:\.\d{1,2})?)/,
191				extract: ({ match }) => {
192					const price = parseFloat(match[1] ?? '');
193					return isNaN(price)
194						? null
195						: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
196				},
197			},
198		];
199	
200		private detectPriceRange({
201			text,
202		}: {
203			text: string;
204		}): { min: number | null; max: number | null } | null {
205			for (const { pattern, extract } of this.PRICE_RANGE_PATTERNS) {
206				const match = pattern.exec(text);
207				if (match) {
208					return extract({ match });
209				}
210			}
211			return null;
212		}
213	
214		private stripContractions({ text }: { text: string }): string {
215			let result = text;
216			for (const contraction of NEURAL_SEARCH_CONTRACTIONS) {
217				result = result.replace(new RegExp(`\\b${contraction}\\b`, 'gi'), '');
218			}
219			return result;
220		}
221	
222		private readonly PRICE_STRIP_PATTERN =
223			/\b(?:under|below|less\s+than|up\s+to|over|above|more\s+than|from|around|about|~)?\s*\$\d+(?:\.\d{1,2})?\s*(?:[-–]\s*\$\d+(?:\.\d{1,2})?)?\b/gi;
224	
225		private detectSize({ text }: { text: string }): string | null {
226			const cleanedText = this.stripContractions({
227				text: text
228					.replace(this.MEASUREMENT_UNITS_PATTERN, '')
229					.replace(this.PRICE_STRIP_PATTERN, ''),
230			});
231			const sorted = [...NEURAL_SEARCH_KNOWN_SIZES].sort((a, b) => b.length - a.length);
232			for (const size of sorted) {
233				const escaped = size.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
234				if (new RegExp(`\\b${escaped}\\b`, 'i').test(cleanedText)) {
235					return size;
236				}
237			}
238			return null;
239		}
240	
241		private readonly GENDER_PRODUCT_TYPE_MAP: {
242			pattern: RegExp;
243			productTypes: string[];
244		}[] = [
245			{
246				pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
247				productTypes: ["Women's"],
248			},
249			{
250				pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
251				productTypes: ['Unisex'],
252			},
253			{
254				pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
255				productTypes: ['Youth'],
256			},
257		];
258	
259		private detectGenderProductTypes({ text }: { text: string }): string[] | null {
260			const productTypes: string[] = [];
261	
262			for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
263				if (pattern.test(text)) {
264					productTypes.push(...types);
265				}
266			}
267	
268			return productTypes.length > 0 ? productTypes : null;
269		}
270	
271		private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
272			{
273				pattern:
274					/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
275				levels: [1],
276			},
277			{
278				pattern:
279					/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
280				levels: [2],
281			},
282			{
283				pattern:
284					/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest|high[\s-]quality)\b/i,
285				levels: [3],
286			},
287		];
288	
289		private detectPriceLevels({ text }: { text: string }): number[] | null {
290			const levels: number[] = [];
291	
292			for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
293				if (pattern.test(text)) {
294					levels.push(...priceLevels);
295				}
296			}
297	
298			return levels.length > 0 ? levels : null;
299		}
300	
301		private sanitizeQuery({ text }: { text: string }): string {
302			return text
303				.trim()
304				.replace(/<[^>]*>/g, ' ')
305				.replace(/[\x00-\x1F\x7F]/g, ' ')
306				.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
307				.replace(/\s{2,}/g, ' ')
308				.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
309				.trim();
310		}
311	
312		private readonly QUERY_SYNONYMS: [RegExp, string][] = [
313			[/\btshirt(s)?\b/gi, 't-shirt$1'],
314			[/\bt shirt(s)?\b/gi, 't-shirt$1'],
315			[/\bv[\s-]?neck\b/gi, 'v-neck'],
316			[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
317			[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
318			[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
319			[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
320			[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
321			[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
322			[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
323			[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
324			[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
325			[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
326			[/\bslim[\s-]?fit\b/gi, 'slim fit'],
327			[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
328		];
329	
330		private normalizeQuery({ text }: { text: string }): string {
331			let normalized = text.toLowerCase().trim();
332	
333			for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
334				normalized = normalized.replace(pattern, replacement);
335			}
336	
337			return normalized;
338		}
339	
340		@LogExecution()
341		async createProductsIndex({ indexName }: { indexName: string }): Promise<void> {
342			const settings = {
343				number_of_shards: 3,
344				number_of_replicas: 1,
345				'index.knn': true,
346				'index.knn.algo_param.ef_search': 512,
347				default_pipeline: 'products-neural-pipeline',
348			};
349	
350			const mappings = {
351				properties: {
352					style_id: { type: 'long' },
353					product_id: { type: 'long' },
354					name: { type: 'text' },
355					features: { type: 'text' },
356					general_comments: { type: 'text' },
357					decoration_method: { type: 'text' },
358					manufacturer: { type: 'text' },
359					primary_category_id: { type: 'integer' },
360					primary_category_name: { type: 'keyword' },
361					product_type: { type: 'keyword' },
362					style_type: { type: 'keyword' },
363					broad_category_names: { type: 'keyword' },
364					sub_category_names: { type: 'keyword' },
365					minimum_quantity: { type: 'integer' },
366					min_qty: { type: 'integer' },
367					default_quote_qty: { type: 'integer' },
368					sizes: { type: 'keyword' },
369					turn_time: { type: 'integer' },
370					rush_turn_time: { type: 'integer' },
371					no_minimum: { type: 'byte' },
372					price_level: { type: 'short' },
373					rating_score: { type: 'float' },
374					rating_count: { type: 'integer' },
375					default_unit_prices: {
376						type: 'nested',
377						properties: {
378							quantity: { type: 'integer' },
379							price: { type: 'keyword' },
380							regular_unit_price: { type: 'keyword' },
381							algorithm: { type: 'keyword' },
382						},
383					},
384					colors: {
385						type: 'nested',
386						properties: {
387							name: { type: 'keyword' },
388							id: { type: 'integer' },
389							rbgs: {
390								type: 'nested',
391								properties: {
392									R: { type: 'short' },
393									G: { type: 'short' },
394									B: { type: 'short' },
395								},
396							},
397							image_url: { type: 'keyword' },
398						},
399					},
400					price: { type: 'float' },
401					style_card_image_url: { type: 'keyword' },
402					link: { type: 'keyword' },
403					brand: { type: 'keyword' },
404					condensed_features: { type: 'keyword' },
405					material: { type: 'keyword' },
406					status: { type: 'keyword' },
407					created_at: { type: 'date' },
408					updated_at: { type: 'date' },
409					deleted_at: { type: 'date' },
410					combined_text_for_embedding: { type: 'text' },
411					product_embedding: {
412						type: 'knn_vector',
413						dimension: 768,
414						method: {
415							name: 'hnsw',
416							space_type: 'l2',
417							engine: 'faiss',
418							parameters: { ef_construction: 512, m: 48 },
419						},
420					},
421				},
422			};
423	
424			await this.opensearchService.createIndex({ indexName, mappings, settings });
425		}
426	
427		@LogExecution({ logParams: false, logResponse: false })
428		async bulkIndexProducts({
429			indexName,
430			styles,
431		}: {
432			indexName: string;
433			styles: IStylesMvBase[];
434		}): Promise<{ indexed: number; errors: number }> {
435			if (styles.length === 0) {
436				return { indexed: 0, errors: 0 };
437			}
438	
439			const documents = styles.map((style) =>
440				this.transformStyleToOpensearchProduct({ style }),
441			);
442	
443			return this.opensearchService.bulkIndex({ indexName, documents });
444		}
445	
446		@LogExecution({
447			paramFormatter: (
448				params: [{ queryText: string; size: number; categoryFilter?: string }],
449			) => ({
450				queryText: params[0].queryText,
451				size: params[0].size,
452				categoryFilter: params[0].categoryFilter,
453			}),
454			responseFormatter: (response: IOpensearchProduct[]) => ({
455				totalResults: response.length,
456			}),
457		})
458		async searchProducts({
459			queryText,
460			size = NEURAL_SEARCH_LIMIT,
461			categoryFilter,
462		}: {
463			queryText: string;
464			size?: number;
465			categoryFilter?: string;
466		}): Promise<IOpensearchProduct[]> {
467			const sanitizedQuery = this.sanitizeQuery({ text: queryText });
468			const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
469			const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
470			const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
471			const brand = this.detectBrand({ text: sanitizedQuery });
472			const detectedColor = this.detectColor({ text: sanitizedQuery });
473			const detectedSize = this.detectSize({ text: sanitizedQuery });
474			const detectedPriceRange = this.detectPriceRange({ text: queryText });
475	
476			const baseFilters: object[] = [
477				{ term: { status: 'active' } },
478				...(categoryFilter
479					? [
480							{
481								bool: {
482									should: [
483										{ term: { broad_category_names: categoryFilter } },
484										{ term: { sub_category_names: categoryFilter } },
485									],
486									minimum_should_match: 1,
487								},
488							},
489						]
490					: []),
491			];
492	
493			const genderBoosts: object[] = genderProductTypes
494				? [{ terms: { product_type: genderProductTypes } }]
495				: [];
496	
497			const priceBoosts: object[] =
498				priceLevels?.map((level) => ({
499					term: { price_level: { value: level } },
500				})) ?? [];
501	
502			const brandBoosts: object[] = brand ? [{ terms: { brand: [brand] } }] : [];
503	
504			const colorBoosts: object[] = detectedColor
505				? [
506						{
507							nested: {
508								path: 'colors',
509								query: {
510									wildcard: {
511										'colors.name': {
512											value: `*${detectedColor.toLowerCase()}*`,
513											case_insensitive: true,
514										},
515									},
516								},
517							},
518						},
519					]
520				: [];
521	
522			const unitPriceBoosts: object[] = detectedPriceRange
523				? [
524						{
525							range: {
526								price: {
527									...(detectedPriceRange.min !== null && { gte: detectedPriceRange.min }),
528									...(detectedPriceRange.max !== null && { lte: detectedPriceRange.max }),
529								},
530							},
531						},
532					]
533				: [];
534	
535			const sizeBoosts: object[] = detectedSize
536				? [
537						{
538							wildcard: {
539								sizes: { value: `*${detectedSize.toLowerCase()}*`, case_insensitive: true },
540							},
541						},
542					]
543				: [];
544	
545			const hits = await this.opensearchService.search({
546				indexName: this.indexName,
547				searchPipeline: 'hybrid-search-pipeline',
548				body: {
549					size,
550					min_score: 0.4,
551					query: {
552						hybrid: {
553							queries: [
554								{
555									bool: {
556										should: [
557											{ match: { name: { query: normalizedQuery, boost: 0.1 } } },
558											{
559												match: {
560													condensed_features: { query: normalizedQuery, boost: 0.3 },
561												},
562											},
563											...priceBoosts,
564											...brandBoosts,
565											...genderBoosts,
566											...colorBoosts,
567											...sizeBoosts,
568											...unitPriceBoosts,
569										],
570										filter: baseFilters,
571									},
572								},
573								{
574									neural: {
575										product_embedding: {
576											query_text: normalizedQuery,
577											model_id: this.getModelId(),
578											k: size * 5,
579											filter: { bool: { filter: baseFilters } },
580										},
581									},
582								},
583							],
584						},
585					},
586					collapse: { field: 'product_id' },
587					_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
588				},
589			});
590	
591			const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
592	
593			return hits.map((hit) => {
594				const product = hit._source as IOpensearchProduct;
595				const imageUrl = detectedColor
596					? this.resolveColorImageUrl({ product, colorName: detectedColor })
597					: null;
598				const normalizedScore = hit._score / maxScore;
599	
600				return {
601					...product,
602					_id: hit._id,
603					confidenceScore: Math.min(Math.round(Math.pow(normalizedScore, 2) * 100), 100),
604					...(imageUrl !== null && { style_card_image_url: imageUrl }),
605				};
606			});
607		}
608	
609		@LogExecution({
610			paramFormatter: (
611				params: [{ categories: Record<string, string>[]; size?: number }],
612			) => ({
613				categories: params[0].categories.map((c) => Object.keys(c)[0]),
614				size: params[0].size,
615			}),
616			responseFormatter: (response: IOpensearchProduct[]) => ({
617				total: response.length,
618			}),
619		})
620		async searchProductsByCategories({
621			categories,
622			size,
623		}: {
624			categories: Record<string, string>[];
625			size?: number;
626		}): Promise<IOpensearchProduct[]> {
627			const effectiveSize = size ?? NEURAL_SEARCH_LIMIT;
628			const perCategory = Math.ceil(effectiveSize / categories.length);
629	
630			const categoryResults = await Promise.all(
631				categories.map((categoryEntry) => {
632					const categoryName = Object.keys(categoryEntry)[0] ?? '';
633					const categoryQueryText = Object.values(categoryEntry)[0] ?? '';
634	
635					return this.searchProducts({
636						queryText: categoryQueryText || categoryName,
637						size: perCategory,
638						categoryFilter: categoryName,
639					});
640				}),
641			);
642	
643			const interleaved: IOpensearchProduct[] = [];
644			const maxLen = Math.max(...categoryResults.map((r) => r.length));
645			for (let i = 0; i < maxLen; i++) {
646				for (const results of categoryResults) {
647					const item = results[i];
648					if (item !== undefined) {
649						interleaved.push(item);
650					}
651				}
652			}
653	
654			return interleaved.slice(0, effectiveSize);
655		}
656	
657		private resolveColorImageUrl({
658			product,
659			colorName,
660		}: {
661			product: IOpensearchProduct;
662			colorName: string;
663		}): string | null {
664			if (!product.colors?.length) return null;
665	
666			const lowerColor = colorName.toLowerCase();
667			const match = product.colors.find((c) => c.name.toLowerCase() === lowerColor);
668	
669			if (match?.image_url) return match.image_url;
670	
671			const partialMatch = product.colors.find((c) =>
672				c.name.toLowerCase().includes(lowerColor),
673			);
674	
675			return partialMatch?.image_url ?? null;
676		}
677	
678		private normalizeCondensedFeatures({
679			condensedFeatures,
680		}: {
681			condensedFeatures: unknown;
682		}): string[] | null {
683			if (condensedFeatures === null || condensedFeatures === undefined) {
684				return null;
685			}
686	
687			if (typeof condensedFeatures === 'string') {
688				return [condensedFeatures];
689			}
690	
691			if (Array.isArray(condensedFeatures)) {
692				return condensedFeatures.map(String);
693			}
694	
695			if (typeof condensedFeatures === 'object') {
696				return Object.values(condensedFeatures).flatMap((value: unknown) =>
697					Array.isArray(value) ? value.map(String) : [String(value)],
698				);
699			}
700	
701			return [JSON.stringify(condensedFeatures)];
702		}
703	
704		private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
705			const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
706				condensedFeatures: style.condensed_features,
707			});
708			const priceLvlMap: Record<string, string> = {
709				1: 'Budget',
710				2: 'Mid-range',
711				3: 'Premium',
712			};
713			const mappedPriceLevel: string | null =
714				style.price_level && priceLvlMap[String(style.price_level)]
715					? (priceLvlMap[String(style.price_level)] ?? null)
716					: (priceLvlMap['2'] ?? null);
717	
718			const parts: string[] = [
719				...(style.name ? [this.cleanText({ text: style.name })] : []),
720				...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
721				...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
722				...(style.brand ? [`Brand: ${this.cleanText({ text: style.brand })}`] : []),
723				...(normalizedCondensedFeatures?.length
724					? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
725					: []),
726				...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
727				...(style.primary_category_name
728					? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
729					: []),
730				...(style.manufacturer
731					? [`From: ${this.cleanText({ text: style.manufacturer })}`]
732					: []),
733				...(style.sub_category_names?.length
734					? [
735							`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
736						]
737					: []),
738				...(style.decoration_method
739					? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
740					: []),
741				...(style.features
742					? [`Features: ${this.cleanText({ text: style.features })}`]
743					: []),
744			];
745	
746			const combinedText = parts.filter(Boolean).join('. ');
747	
748			this.logger.debug(
749				`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
750			);
751	
752			return combinedText;
753		}
754	
755		private extractPrice({
756			prices,
757		}: {
758			prices: IOpensearchProduct['default_unit_prices'];
759		}): number | null {
760			if (!prices?.length) return null;
761			const first = prices[0];
762			if (!first) return null;
763			const parsed = parseFloat(first.price);
764			return isNaN(parsed) ? null : parsed;
765		}
766	
767		private cleanText({ text }: { text: string | null | undefined }): string {
768			if (!text) return '';
769			return text
770				.replace(/\r\n|\r|\n/g, ' ')
771				.replace(/[*#]+\s?/g, '')
772				.replace(/<[^>]*>/g, '')
773				.replace(/\s{2,}/g, ' ')
774				.trim();
775		}
776	
777		private transformStyleToOpensearchProduct({
778			style,
779		}: {
780			style: IStylesMvBase;
781		}): IOpensearchProduct {
782			return {
783				_id: style._id,
784				style_id: style.style_id,
785				product_id: style.product_id,
786				name: style.name ?? '',
787				features: style.features,
788				general_comments: style.general_comments,
789				decoration_method: style.decoration_method,
790				manufacturer: style.manufacturer,
791				primary_category_id: style.primary_category_id,
792				primary_category_name: style.primary_category_name,
793				product_type: style.product_type,
794				style_type: style.style_type,
795				broad_category_names: style.broad_category_names,
796				sub_category_names: style.sub_category_names,
797				minimum_quantity: style.minimum_quantity,
798				min_qty: style.min_qty,
799				default_quote_qty: style.default_quote_qty,
800				sizes: style.sizes,
801				turn_time: style.turn_time,
802				rush_turn_time: style.rush_turn_time,
803				no_minimum: style.no_minimum ? 1 : 0,
804				price_level: style.price_level,
805				rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
806				rating_count: style.rating_count,
807				default_unit_prices: style.default_unit_prices,
808				price: this.extractPrice({ prices: style.default_unit_prices }),
809				colors: style.colors,
810				style_card_image_url: style.style_card_image_url,
811				link: style.link,
812				brand: style.brand ? [style.brand] : null,
813				condensed_features: this.normalizeCondensedFeatures({
814					condensedFeatures: style.condensed_features,
815				}),
816				material: style.material,
817				status: style.status,
818				created_at:
819					style.created_at instanceof Date
820						? style.created_at.toISOString()
821						: String(style.created_at),
822				updated_at:
823					style.updated_at instanceof Date
824						? style.updated_at.toISOString()
825						: String(style.updated_at),
826				deleted_at: style.deleted_at
827					? style.deleted_at instanceof Date
828						? style.deleted_at.toISOString()
829						: String(style.deleted_at)
830					: null,
831				combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
832			};
833		}
834	}
