1	import { BadRequestException, Injectable } from '@nestjs/common';
2	
3	import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
4	
5	import { NEURAL_SEARCH_TAG_CATEGORY_NAMES } from '@constants/neural-search.constant';
6	
7	import { LogExecution } from '@decorators/log-execution.decorator';
8	
9	import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
10	import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';
11	import { NeuralSearchUseCaseResponseDto } from '@dto/neural-search/neural-search-use-case-response.dto';
