13	@Injectable()
14	export class NeuralSearchService {
15		constructor(private readonly opensearchNeuralService: OpensearchNeuralService) {}
16	
17		@LogExecution({
18			paramFormatter: (params: [NeuralSearchQueryDto]) => ({
19				q: params[0].q,
20				limit: params[0].limit,
21			}),
22			responseFormatter: (response: NeuralSearchResponseDto) => ({
23				total: response.total,
24			}),
25		})
26		async search({
27			query,
28		}: {
29			query: NeuralSearchQueryDto;
30		}): Promise<NeuralSearchResponseDto> {
31			const products = await this.opensearchNeuralService.searchProducts({
32				queryText: query.q,
33				...(query.limit !== undefined && { size: query.limit }),
34			});
35	
36			return {
37				query: query.q,
38				total: products.length,
39				products,
40			};
41		}
42	
43		@LogExecution({
44			paramFormatter: (params: [{ useCase: string; limit?: number }]) => ({
45				useCase: params[0].useCase,
46				limit: params[0].limit,
47			}),
48			responseFormatter: (response: NeuralSearchUseCaseResponseDto) => ({
49				total: response.total,
50			}),
51		})
52		async getProductsByUseCase({
53			useCase,
54			limit,
55		}: {
56			useCase: string;
57			limit?: number;
58		}): Promise<NeuralSearchUseCaseResponseDto> {
59			const categories = NEURAL_SEARCH_TAG_CATEGORY_NAMES[useCase];
60	
61			if (!categories) {
62				const validUseCases = Object.keys(NEURAL_SEARCH_TAG_CATEGORY_NAMES).join(', ');
63				throw new BadRequestException(
64					`Invalid use-case "${useCase}". Valid options: ${validUseCases}`,
65				);
66			}
67	
68			const products = await this.opensearchNeuralService.searchProductsByCategories({
69				categories,
70				...(limit !== undefined && { size: limit }),
71			});
72	
73			return {
74				useCase,
75				total: products.length,
76				products,
77			};
78		}
