89					<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
90					<div style="margin-top:4px;font-size:11px;color:#2563eb;font-weight:500;">Confidence: ${String(p.confidenceScore ?? 0)}%</div>
91					<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
92					<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
