96				</div>`,
97						)
98						.join('')
99				: '';
100	
101			const resultsSection = result
102				? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong> | Results: ${result.total}</p>
103				<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
104				: '';
105	
106			return `<!DOCTYPE html>
107	<html><head><meta charset="utf-8"><title>Neural Search</title></head>
108	<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
109		<h2>Neural Search</h2>
110		<form id="searchForm" style="margin-bottom:16px;">
111			<div style="display:flex;gap:8px;margin-bottom:8px;">
112				<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
113					style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
114				<button type="submit"
115					style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
116					Ask AI
117				</button>
118			</div>
